package main

import (
    "fmt"
    "errors"
)

// ---- Basic function ----
func add(a int, b int) int {
    return a + b
}

// ---- Multiple parameters of same type ----
func multiply(a, b int) int {
    return a * b
}

// ---- Multiple return values ----
func divide(a, b int) (int, error) {
    if b == 0 {
        return 0, errors.New("division by zero")
    }
    return a / b, nil
}

// ---- Named return values ----
func swap(a, b int) (x, y int) {
    x = b
    y = a
    return  // Naked return
}

// ---- Function with multiple parameters and return ----
func calculate(a, b int) (sum, diff, product int) {
    sum = a + b
    diff = a - b
    product = a * b
    return
}

// ---- Variadic function ----
func sumAll(numbers ...int) int {
    total := 0
    for _, n := range numbers {
        total += n
    }
    return total
}

// ---- Function as value ----
var addFunc = func(a, b int) int {
    return a + b
}

func main() {
    // ---- Basic function ----
    fmt.Println("Add:", add(5, 3))
    fmt.Println("Multiply:", multiply(5, 3))

    // ---- Multiple returns ----
    result, err := divide(10, 2)
    if err != nil {
        fmt.Println("Error:", err)
    } else {
        fmt.Println("Divide:", result)
    }

    // ---- Error case ----
    result2, err2 := divide(10, 0)
    if err2 != nil {
        fmt.Println("Error:", err2)
    } else {
        fmt.Println("Divide:", result2)
    }

    // ---- Named returns ----
    x, y := swap(10, 20)
    fmt.Println("Swap:", x, y)

    // ---- Multiple returns ----
    sum, diff, product := calculate(10, 5)
    fmt.Println("Sum:", sum)
    fmt.Println("Diff:", diff)
    fmt.Println("Product:", product)

    // ---- Variadic ----
    fmt.Println("Sum all:", sumAll(1, 2, 3, 4, 5))
    fmt.Println("Sum all:", sumAll(10, 20, 30))

    // ---- Function as value ----
    fmt.Println("Add func:", addFunc(5, 3))
}

phase1.explanation:
🦫 **Functions in Go can return multiple values.**

**Function syntax:**
```go
func name(parameters) returnType {
    // body
}
```

**Multiple returns:**
```go
func divide(a, b int) (int, error) {
    return a / b, nil
}
```

**Named returns:**
```go
func swap(a, b int) (x, y int) {
    x = b
    y = a
    return
}
```

**Variadic functions:**
```go
func sumAll(numbers ...int) int {
    // numbers is a slice
}
```

**Go-chan says:**
"Multiple returns are the standard. Return errors, not exceptions."

**When to use named returns:**
- Document what the function returns
- Short functions where it's obvious
- Not for complex functions

