package main

import (
    "fmt"
    "errors"
)

func add(a, b int) int {
    return a + b
}

func divide(a, b int) (int, error) {
    if b == 0 {
        return 0, errors.New("division by zero")
    }
    return a / b, nil
}

func stats(a, b int) (sum, diff, product int) {
    sum = a + b
    diff = a - b
    product = a * b
    return
}

func main() {
    fmt.Println("Add:", add(10, 5))

    result, err := divide(10, 2)
    if err != nil {
        fmt.Println("Error:", err)
    } else {
        fmt.Println("Divide:", result)
    }

    sum, diff, product := stats(10, 5)
    fmt.Println("Stats:", sum, diff, product)
}
